// lib/larvae-survey.ts
//
// Larvae Survey Game — survey-board game built from real larva responses.
//
// Boards are PRE-GENERATED by the build route and cached in Redis, so gameplay
// is instant. Generating one board = N in-character responses (one Haiku call
// per larva, run with limited concurrency) + one clustering call that groups
// those responses into ranked board answers.
//
// Guess matching is two-tier: a free normalized/substring pass first, then a
// single Haiku call only when that misses. Obvious hits cost nothing.
//
// Imports only redis + haiku + getIndex + getProfile from lib/larvae.ts —
// nothing in the existing codebase is modified.

import { redis, haiku, getIndex, getProfile } from "@/lib/larvae";

// ─── Types ─────────────────────────────────────────────────────────

/** One clustered answer on the board. */
export type BoardAnswer = {
  rank: number; // 1 = most common
  label: string; // short board text, e.g. "VAGUE ROADMAPS"
  count: number; // how many larvae gave this answer
  points: number; // count, used directly as score
  /** Names of the larvae whose responses landed in this cluster. */
  voices: string[];
  /** One representative quote, for the reveal. */
  sample: string;
};

/** A complete playable board. */
export type SurveyBoard = {
  id: string;
  question: string;
  answers: BoardAnswer[];
  respondents: number; // how many larvae were surveyed
  totalPoints: number;
  builtAt: string;
};

/** Raw survey response before clustering. */
type SurveyResponse = {
  wallet: string;
  name: string;
  answer: string;
};

// ─── Question set ──────────────────────────────────────────────────
//
// Seed list is the starting bank. Runtime questions live in Redis so minting
// can grow the pool without a deploy. Build always reads the bank.

export type SurveyQuestion = {
  id: string;
  text: string;
  source: "seed" | "minted";
  createdAt: string;
};

