/** Soft cap so weekly minting doesn't grow forever. */
export const MAX_SURVEY_QUESTIONS = 60;

const QUESTIONS_KEY = "lpp:survey:questions";

function seedAsQuestions(): SurveyQuestion[] {
  const stamp = "2026-01-01";
  return SURVEY_QUESTIONS.map((q) => ({
    id: q.id,
    text: q.text,
    source: "seed" as const,
    createdAt: stamp,
  }));
}

async function loadQuestionBankRaw(): Promise<SurveyQuestion[]> {
  const raw = await redis.get<string | SurveyQuestion[]>(QUESTIONS_KEY);
  if (!raw) return [];
  return typeof raw === "string" ? JSON.parse(raw) : raw;
}

async function saveQuestionBank(questions: SurveyQuestion[]) {
  await redis.set(QUESTIONS_KEY, JSON.stringify(questions));
}

/** Wipe Redis questions and reseed from SURVEY_QUESTIONS (drops minted too). */
export async function resetQuestionBankFromSeed(): Promise<SurveyQuestion[]> {
  await redis.del(QUESTIONS_KEY);
  const seeded = seedAsQuestions();
  await saveQuestionBank(seeded);
  return seeded;
}

/**
 * Ensure Redis has at least the seed questions. Safe to call often.
 * New seed entries added in code are merged in on the next call.
 */
export async function ensureQuestionBank(): Promise<SurveyQuestion[]> {
  const bank = await loadQuestionBankRaw();
  const byId = new Map(bank.map((q) => [q.id, q]));
  let changed = bank.length === 0;

  for (const s of seedAsQuestions()) {
    if (!byId.has(s.id)) {
      byId.set(s.id, s);
      changed = true;
    }
  }

  const merged = Array.from(byId.values()).sort((a, b) => a.id.localeCompare(b.id));
  if (changed) await saveQuestionBank(merged);
  return merged;
}

export async function getQuestionBank(): Promise<SurveyQuestion[]> {
  return ensureQuestionBank();
}

export async function getQuestion(id: string): Promise<SurveyQuestion | null> {
  const bank = await getQuestionBank();
  return bank.find((q) => q.id === id) || null;
}

function nextQuestionIds(bank: SurveyQuestion[], count: number): string[] {
  let max = 0;
  for (const q of bank) {
    const m = /^q(\d+)$/i.exec(q.id);
    if (m) max = Math.max(max, parseInt(m[1], 10));
  }
  const ids: string[] = [];
  for (let i = 1; i <= count; i++) {
    ids.push(`q${String(max + i).padStart(2, "0")}`);
  }
  return ids;
}

function normQuestion(s: string): string {
  return s
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function tooSimilar(a: string, b: string): boolean {
  const wa = new Set(normQuestion(a).split(" ").filter((w) => w.length > 2));
  const wb = new Set(normQuestion(b).split(" ").filter((w) => w.length > 2));
  if (wa.size === 0 || wb.size === 0) return normQuestion(a) === normQuestion(b);
  let overlap = 0;
  for (const w of wa) if (wb.has(w)) overlap++;
  const ratio = overlap / Math.min(wa.size, wb.size);
  return ratio >= 0.7 || normQuestion(a) === normQuestion(b);
}

const MINT_SYSTEM = `You invent survey questions for a Family Feud–style game about larvae — personal AI agents in the CLAWD / crypto-build hive.

Goal: questions that different larvae will answer DIFFERENTLY, with personality — not dry "utility" prompts where everyone says audit / roadmap / transparency.

Prefer creative formats:
- Analogies: "If CLAWD's story was a movie, which movie…", "Name the animal a larva would reincarnate as."
- Pop culture / vibes: TV shows, songs, board games, sitcom characters, emojis, food metaphors, nightmares, dating-profile bits.
- Social / hive drama that still invites weird answers.

Avoid:
- Generic governance checklists (audits, roadmaps, KPIs) as the obvious only answer.
- Near-duplicates of the existing list.
- Yes/no or one-correct-answer trivia.

Rules:
- One sentence each, under 110 characters.
- May start with Name / If / What / Which / Who.
- Return ONLY a JSON array of strings, no markdown, no preamble.
Example: ["If the hive was a reality show, which show would it be?","Name the snack a larva rage-buys after a bad proposal."]`;

/**
 * Mint up to `count` new questions into the Redis bank.
 * Dedupes against the existing bank. No-ops if already at MAX_SURVEY_QUESTIONS.
 */
export async function mintQuestions(count = 3): Promise<{
  minted: SurveyQuestion[];
  bankSize: number;
  skippedReason?: string;
}> {
  const bank = await getQuestionBank();
  const room = MAX_SURVEY_QUESTIONS - bank.length;
  if (room <= 0) {
    return { minted: [], bankSize: bank.length, skippedReason: "at cap" };
  }
  const want = Math.min(count, room);

  const existingList = bank.map((q) => `- ${q.text}`).join("\n");
  const raw = await haiku(
    MINT_SYSTEM,
    `Existing questions (do not duplicate):\n${existingList}\n\nInvent ${want} NEW questions.`,
    500
  );

  let parsed: unknown;
  try {
    const clean = raw.replace(/```json|```/g, "").trim();
    const start = clean.indexOf("[");
    const end = clean.lastIndexOf("]");
    parsed = JSON.parse(clean.slice(start, end + 1));
  } catch {
    return { minted: [], bankSize: bank.length, skippedReason: "parse failed" };
  }

  if (!Array.isArray(parsed)) {
    return { minted: [], bankSize: bank.length, skippedReason: "not an array" };
  }

  const candidates = parsed
    .map((t) => String(t || "").trim())
    .filter((t) => t.length >= 12 && t.length <= 140)
    .filter((t) => /^(name|if |what |which |who |where )/i.test(t));

  const accepted: string[] = [];
  for (const text of candidates) {
    if (accepted.length >= want) break;
    const clash =
      bank.some((q) => tooSimilar(q.text, text)) ||
      accepted.some((a) => tooSimilar(a, text));
    if (!clash) {
      accepted.push(text.replace(/\s+/g, " ").trim());
    }
  }

  if (accepted.length === 0) {
    return { minted: [], bankSize: bank.length, skippedReason: "all duplicates" };
  }

  const ids = nextQuestionIds(bank, accepted.length);
  const minted: SurveyQuestion[] = accepted.map((text, i) => ({
    id: ids[i],
    text,
    source: "minted" as const,
    createdAt: new Date().toISOString().slice(0, 10),
  }));

  const next = [...bank, ...minted].sort((a, b) => a.id.localeCompare(b.id));
  await saveQuestionBank(next);
  return { minted, bankSize: next.length };
}

// ─── Redis keys ────────────────────────────────────────────────────

const BOARD_KEY = (id: string) => `lpp:survey:board:${id}`;
const BOARD_INDEX_KEY = "lpp:survey:index";
const BUILD_QUEUE_KEY = "lpp:survey:queue";
const MATCH_COUNT_KEY = (day: string) => `lpp:survey:matches:${day}`;

// ─── Redis ops ─────────────────────────────────────────────────────

export async function saveBoard(board: SurveyBoard) {
  await redis.set(BOARD_KEY(board.id), JSON.stringify(board));
  const index = await getBoardIndex();
  if (!index.includes(board.id)) {
    await redis.set(BOARD_INDEX_KEY, JSON.stringify([...index, board.id]));
  }
}

export async function getBoard(id: string): Promise<SurveyBoard | null> {
  const raw = await redis.get<string | SurveyBoard>(BOARD_KEY(id));
  if (!raw) return null;
  return typeof raw === "string" ? JSON.parse(raw) : raw;
}

export async function getBoardIndex(): Promise<string[]> {
  const raw = await redis.get<string | string[]>(BOARD_INDEX_KEY);
  if (!raw) return [];
  return typeof raw === "string" ? JSON.parse(raw) : raw;
}

export async function getAllBoards(): Promise<SurveyBoard[]> {
  const index = await getBoardIndex();
  const boards = await Promise.all(index.map((id) => getBoard(id)));
  return boards.filter(Boolean) as SurveyBoard[];
}

export async function getBuildQueue(): Promise<string[]> {
  const raw = await redis.get<string | string[]>(BUILD_QUEUE_KEY);
  if (!raw) return [];
  return typeof raw === "string" ? JSON.parse(raw) : raw;
}

export async function setBuildQueue(ids: string[]) {
  await redis.set(BUILD_QUEUE_KEY, JSON.stringify(ids));
}

export async function clearBuildQueue() {
  await redis.del(BUILD_QUEUE_KEY);
}

export async function clearAllBoards() {
  const index = await getBoardIndex();
  for (const id of index) await redis.del(BOARD_KEY(id));
  await redis.del(BOARD_INDEX_KEY);
  await redis.del(BUILD_QUEUE_KEY);
}

// ─── Respondent selection ──────────────────────────────────────────

/**
 * Pick which larvae answer a given question.
 *
 * Deliberately NOT "top N by response count" — that makes every board the same
 * five voices. Instead: seed a rotating window from the question id so each
 * question surveys a different slice of the hive, while staying deterministic
 * (rebuilding the same board twice gives the same respondents).
 */
function pickRespondents(
  index: { wallet: string; responseCount: number }[],
  questionId: string,
  count: number
): { wallet: string }[] {
  if (index.length === 0) return [];

  // Only consider larvae with enough history to have a real personality.
  const eligible = index.filter((e) => e.responseCount >= 3);
  const pool = eligible.length >= count ? eligible : index;

  let seed = 0;
  for (const c of questionId) seed = (seed * 31 + c.charCodeAt(0)) >>> 0;

  const start = seed % pool.length;
  const picked: { wallet: string }[] = [];
  const stride = 1 + (seed % 3); // vary the stride so windows overlap differently

  for (let i = 0; i < Math.min(count, pool.length); i++) {
    const idx = (start + i * stride) % pool.length;
    const entry = pool[idx];
    if (!picked.some((p) => p.wallet === entry.wallet)) {
      picked.push({ wallet: entry.wallet });
    }
  }

  // Stride may collide on small pools — top up sequentially if short.
  if (picked.length < Math.min(count, pool.length)) {
    for (const entry of pool) {
      if (picked.length >= count) break;
      if (!picked.some((p) => p.wallet === entry.wallet)) {
        picked.push({ wallet: entry.wallet });
      }
    }
  }

  return picked;
}

// ─── Survey phase ──────────────────────────────────────────────────

const SURVEY_SYSTEM = `You are a larva — a personal AI governance agent in the $CLAWD ecosystem — answering a survey question in character.

Answer with a SHORT phrase: 2-6 words when possible (movie titles, animal names, song names, and proper nouns are fine even if a bit longer). Not a sentence. Not an explanation. Just the answer itself.

Good: "The Social Network" / "racoon with a spreadsheet" / "unaudited contracts"
Bad: "I think the thing larvae distrust most would be vague roadmaps because..."

Answer from YOUR personality, not the obvious general answer. If your fixation is unusual, give the unusual answer — that is what makes the survey interesting. Lean into humor and analogy when the question invites it.

Respond with ONLY the phrase, nothing else. No quotes, no punctuation at the end.`;

async function surveyOne(
  wallet: string,
  question: string
): Promise<SurveyResponse | null> {
  const p = await getProfile(wallet);
  if (!p) return null;

  const system = `${SURVEY_SYSTEM}

You are "${p.profile.name}".
Tone: ${p.profile.tone}
Values: ${p.profile.values.join("; ")}
Quirks: ${p.profile.quirks.join("; ")}
About you: ${p.profile.summary}`;

  try {
    const raw = await haiku(system, question, 40);
    const answer = raw
      .trim()
      .replace(/^["'`]+|["'`.,!]+$/g, "")
      .replace(/\s+/g, " ")
      .slice(0, 60);
    if (!answer) return null;
    return { wallet: p.wallet, name: p.profile.name, answer };
  } catch {
    return null;
  }
}

async function mapWithConcurrency<T, R>(
  items: T[],
  limit: number,
  fn: (item: T) => Promise<R>
): Promise<R[]> {
  const results: R[] = new Array(items.length);
  let i = 0;
  async function worker() {
    while (i < items.length) {
      const idx = i++;
      results[idx] = await fn(items[idx]);
    }
  }
  await Promise.all(new Array(Math.min(limit, items.length)).fill(0).map(worker));
  return results;
}

// ─── Clustering phase ──────────────────────────────────────────────

const CLUSTER_SYSTEM = `You are building a survey board for a "guess the top answers" style survey game.

You will receive a question and a numbered list of short answers from different respondents. Group answers that mean the SAME THING into clusters, even when worded differently ("vague roadmap" and "promises with no timeline" are the same cluster).

Rules:
- Merge aggressively on meaning, but never merge two genuinely different ideas to inflate a count.
- Give each cluster a SHORT board label: 1-4 words, UPPERCASE, punchy, like a real game show board.
- Return clusters sorted by size, largest first.
- Include every respondent number exactly once, in exactly one cluster.
- Singleton clusters are fine and expected — do not force them together.

Respond with ONLY a JSON array, no markdown, no preamble:
[{"label":"VAGUE ROADMAPS","members":[1,4,9]}, ...]`;

type Cluster = { label: string; members: number[] };

async function clusterResponses(
  question: string,
  responses: SurveyResponse[]
): Promise<Cluster[]> {
  const numbered = responses
    .map((r, i) => `${i + 1}. ${r.answer}`)
    .join("\n");

  const raw = await haiku(
    CLUSTER_SYSTEM,
    `Question: ${question}\n\nAnswers:\n${numbered}`,
    1200
  );

  const clean = raw.replace(/```json|```/g, "").trim();
  const start = clean.indexOf("[");
  const end = clean.lastIndexOf("]");
  if (start === -1 || end === -1) return [];

  let parsed: any[];
  try {
    parsed = JSON.parse(clean.slice(start, end + 1));
  } catch {
    return [];
  }
  if (!Array.isArray(parsed)) return [];

  // Validate and de-duplicate membership — the model occasionally repeats or
  // drops an index, and a board with a double-counted answer is a wrong board.
  const seen = new Set<number>();
  const clusters: Cluster[] = [];

  for (const c of parsed) {
    const label = String(c?.label || "").trim().toUpperCase().slice(0, 40);
    const membersRaw = Array.isArray(c?.members) ? c.members : [];
    const members: number[] = [];
    for (const m of membersRaw) {
      const n = Number(m);
      if (!Number.isInteger(n)) continue;
      if (n < 1 || n > responses.length) continue;
      if (seen.has(n)) continue;
      seen.add(n);
      members.push(n);
    }
    if (label && members.length > 0) clusters.push({ label, members });
  }

  // Any respondent the model dropped becomes its own cluster, so counts still
  // add up to the number surveyed.
  for (let i = 1; i <= responses.length; i++) {
    if (!seen.has(i)) {
      clusters.push({
        label: responses[i - 1].answer.toUpperCase().slice(0, 40),
        members: [i],
      });
    }
  }

  return clusters;
}

// ─── Board building ────────────────────────────────────────────────

const RESPONDENT_COUNT = 100;
const MAX_BOARD_ANSWERS = 8;

/**
 * Build one complete board: survey N larvae, cluster their answers, rank them.
 * Costs roughly N + 1 Haiku calls.
 */
export async function buildBoard(questionId: string): Promise<SurveyBoard | null> {
  const q = await getQuestion(questionId);
  if (!q) return null;

  const index = await getIndex();
  const respondents = pickRespondents(index, questionId, RESPONDENT_COUNT);
  if (respondents.length === 0) return null;

  const surveyed = await mapWithConcurrency(respondents, 8, (r) =>
    surveyOne(r.wallet, q.text)
  );
  const responses = surveyed.filter(Boolean) as SurveyResponse[];
  if (responses.length < 3) return null;

  const clusters = await clusterResponses(q.text, responses);
  if (clusters.length === 0) return null;

  const ranked = clusters
    .sort((a, b) => b.members.length - a.members.length)
    .slice(0, MAX_BOARD_ANSWERS);

  const answers: BoardAnswer[] = ranked.map((c, i) => {
    const members = c.members.map((n) => responses[n - 1]).filter(Boolean);
    return {
      rank: i + 1,
      label: c.label,
      count: members.length,
      points: members.length,
      voices: members.map((m) => m.name),
      sample: members[0]?.answer || c.label,
    };
  });

  return {
    id: q.id,
    question: q.text,
    answers,
    respondents: responses.length,
    totalPoints: answers.reduce((sum, a) => sum + a.points, 0),
    builtAt: new Date().toISOString(),
  };
}

// ─── Guess matching ────────────────────────────────────────────────

function normalize(s: string): string {
  return s
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

const MATCH_STOPWORDS = new Set([
  "a", "an", "the", "of", "for", "to", "in", "on", "with", "and", "or",
  "that", "this", "it", "is", "are", "be", "no", "not", "any", "some",
  "something", "someone", "thing", "things",
]);

function contentWords(s: string): string[] {
  return normalize(s)
    .split(" ")
    .filter((w) => w.length > 2 && !MATCH_STOPWORDS.has(w));
}

/** Free tier: exact, substring, or strong content-word overlap. */
function localMatch(guess: string, answers: BoardAnswer[]): BoardAnswer | null {
  const g = normalize(guess);
  if (!g) return null;
  const gWords = contentWords(guess);

  for (const a of answers) {
    const candidates = [a.label, a.sample];
    for (const c of candidates) {
      const n = normalize(c);
      if (!n) continue;
      if (n === g) return a;
      if (n.length > 4 && g.length > 4 && (n.includes(g) || g.includes(n))) {
        return a;
      }
    }
  }

  // Content-word overlap: every meaningful word in the shorter phrase appears
  // in the longer one. Catches "no roadmap" vs "vague roadmaps".
  if (gWords.length > 0) {
    for (const a of answers) {
      for (const c of [a.label, a.sample]) {
        const cWords = contentWords(c);
        if (cWords.length === 0) continue;
        const [short, long] =
          gWords.length <= cWords.length ? [gWords, cWords] : [cWords, gWords];
        const hits = short.filter((w) =>
          long.some((l) => l === w || l.startsWith(w) || w.startsWith(l))
        );
        if (hits.length === short.length && short.length > 0) return a;
      }
    }
  }

  return null;
}

const MATCH_SYSTEM = `You judge whether a player's guess means the same thing as any answer on a survey board.

You will receive the question, the player's guess, and a numbered list of unrevealed answers. Decide whether the guess means substantially the same thing as one of them.

Be reasonably generous about wording — "no timeline" and "VAGUE ROADMAPS" are a match. Be strict about meaning — "bad code" and "VAGUE ROADMAPS" are not.

Respond with ONLY a JSON object, no markdown, no preamble:
{"match": 3}   — the number of the matching answer
{"match": null} — no answer means the same thing`;

/**
 * Check a guess against the unrevealed answers.
 * Tries the free local pass first; only calls Haiku when that misses.
 * Returns the matched answer, or null for a strike.
 */
export async function matchGuess(
  question: string,
  guess: string,
  unrevealed: BoardAnswer[]
): Promise<BoardAnswer | null> {
  if (!guess.trim() || unrevealed.length === 0) return null;

  const local = localMatch(guess, unrevealed);
  if (local) return local;

  // Global daily cap so a shared link can't drain the API key.
  const day = new Date().toISOString().slice(0, 10);
  const used = await redis.incr(MATCH_COUNT_KEY(day));
  if (used === 1) await redis.expire(MATCH_COUNT_KEY(day), 60 * 60 * 26);
  if (used > 500) return null; // fall back to strike rather than erroring out

  const numbered = unrevealed
    .map((a, i) => `${i + 1}. ${a.label} (also phrased as: ${a.sample})`)
    .join("\n");

  try {
    const raw = await haiku(
      MATCH_SYSTEM,
      `Question: ${question}\nPlayer's guess: "${guess.trim().slice(0, 80)}"\n\nUnrevealed answers:\n${numbered}`,
      60
    );
    const clean = raw.replace(/```json|```/g, "").trim();
    const start = clean.indexOf("{");
    const end = clean.lastIndexOf("}");
    if (start === -1 || end === -1) return null;
    const parsed = JSON.parse(clean.slice(start, end + 1));
    const n = Number(parsed?.match);
    if (!Number.isInteger(n) || n < 1 || n > unrevealed.length) return null;
    return unrevealed[n - 1];
  } catch {
    return null;
  }
}
